mapper.select:
        select b.id , b.staff_id as staffId, b.type, b.name, b.gender, b.phone, b.id_card as idCard, b.remark,b.reason,
        b.create_by as createBy,
        b.create_time as createTime from blacklist b where 1 = 1

            and b.staff_id =#{staffId}



            and b.type =#{type}




				and b.name like CONCAT('%', #{name}, '%')




            and b.phone = #{phone}



            and b.id_card = #{idCard}

        order by b.create_time DESC
